const results = $input.first().json.results || [];
const g = $('Build gateB').first().json;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
const total = results.length;
if (pending.length === 0) {
  return [{ json: { has_next: false, tg_message: '全套完成 共 ' + total + ' 棒已全部通過 (全自動模式)。' } }];
}
const p = pending[0];
const db06_id = p.id.replace(/-/g, '');
const ai_mode = p.properties['ai模式']?.select?.name || '';
let runner_url;
const _b = 'https://makesense.zeabur.app/webhook/';
if (ai_mode.includes('聯想')) runner_url = _b + 'db06-lianxiang-traversal';
else if (ai_mode.includes('搜查')) runner_url = _b + 'db06-search';
else if (ai_mode.includes('分析')) runner_url = _b + 'db06-analyze';
else if (ai_mode.includes('文案')) runner_url = _b + 'db06-copy';
else if (ai_mode.includes('檢核')) runner_url = _b + 'db06-check';
else runner_url = _b + 'db06-plan';
return [{ json: { has_next: true, db06_id, runner_url, tg_message: '' } }];

const pc = $('Parse Claude').first().json;
const results = pc.results || [];
const NHEAD = {'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const norm = id => (id||'').replace(/-/g,'');
const DB06_DB = '3469ff25fdab83c98ff98107ee6a6a1c';
const target_id = norm(pc.db05_id);
let created=0, linked=0; const refIds=[]; const log=[];
for (const r of results) {
  const url=(r.url||'').toString();
  let pageId='';
  try {
    const q=await this.helpers.httpRequest({method:'POST',url:'https://api.notion.com/v1/databases/'+DB06_DB+'/query',headers:NHEAD,body:JSON.stringify({filter:{property:'對應連結',url:{equals:url}},page_size:1})});
    const qq=(typeof q==='string')?JSON.parse(q):q;
    if(qq.results&&qq.results.length){ pageId=norm(qq.results[0].id); linked++; }
  } catch(e){}
  if(!pageId){
    try {
      const body={parent:{database_id:DB06_DB},properties:{
        '明細名稱':{title:[{text:{content:(r.title||'參考資料').slice(0,200)}}]},
        '明細類型':{select:{name:'資料參考'}},
        '參考類別':{select:{name:'企劃參考'}},
        '對應連結':{url:url||null}
      },children:[
        {object:'block',type:'paragraph',paragraph:{rich_text:[{text:{content:(r.content||'(無摘要)').slice(0,1900)}}]}},
        {object:'block',type:'paragraph',paragraph:{rich_text:[{text:{content:'來源：'+url}}]}}
      ]};
      const cp=await this.helpers.httpRequest({method:'POST',url:'https://api.notion.com/v1/pages',headers:NHEAD,body:JSON.stringify(body)});
      const cpr=(typeof cp==='string')?JSON.parse(cp):cp;
      if(cpr.id){ pageId=norm(cpr.id); created++; }
    } catch(e){ log.push('建頁失敗 '+(r.title||'').slice(0,16)); }
  }
  if(pageId) refIds.push(pageId);
}
let newLinks=0;
try {
  const tp=await this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+target_id,headers:NHEAD});
  const tpr=(typeof tp==='string')?JSON.parse(tp):tp;
  const existing=(((tpr.properties||{})['明細引用']||{}).relation||[]).map(x=>norm(x.id));
  const merged=[...new Set(existing.concat(refIds))];
  newLinks=merged.length-existing.length;
  await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/pages/'+target_id,headers:NHEAD,body:JSON.stringify({properties:{'明細引用':{relation:merged.map(id=>({id}))}}})});
} catch(e){ log.push('連 target 明細引用失敗: '+(e&&e.message||e)); }
const d=new Date(); const tw=new Date(d.getTime()+8*3600*1000);
const ts=tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
const search_summary='── '+ts+' 搜查 ──\n工作對象：'+pc.target_name+'\n做了什麼：Tavily 搜尋「'+(pc.query||'').slice(0,40)+'」採集 '+results.length+' 筆,新建資料參考 '+created+' 筆、查重沿用 '+linked+' 筆,共 '+refIds.length+' 筆寫入 target「明細引用」(本次新增連結 '+newLinks+')\n來源分佈：'+pc.dist_line+'\n未做：'+(log.length?log.slice(0,5).join('；'):'—');
const sanitize=s=>(s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/\s+/g,' ').trim().slice(0,500);
return [{json:{db06_id:pc.db06_id,db05_id:pc.db05_id,ai_mode:pc.ai_mode,sort_num:pc.sort_num,count:results.length,created,linked,ref_count:refIds.length,search_summary,safe_summary:sanitize(search_summary),usage_line:'Tavily 採集 '+results.length+' 筆,新建 '+created,dist_line:pc.dist_line,has_results:results.length>0}}];
